import { Button } from '@fs/zion-ui'
import React, { useState } from 'react'
import { useTranslation } from 'react-i18next'
import { Arrow, NoticeLoading } from '@fs/zion-icon'
import useChatLog from '../hooks/useChatLog'
import useHandleChatErrors from '../hooks/useHandleChatErrors'

export default function ShowMoreChannels({ channelType, handleShowMoreClick }) {
  const [t] = useTranslation()
  const [loading, setLoading] = useState(false)
  const { log, track } = useChatLog({ component: '[ShowMoreChannels]' })
  const { handleBasicError } = useHandleChatErrors({ log })

  const handleClick = () => {
    try {
      setLoading(true)
      track({ link_name: `Chat:Show More Channels: ${channelType}` })

      handleShowMoreClick()
    } catch (err) {
      handleBasicError(err, { moreInfo: `Problem showing more channels: ${channelType}` })
    }
    setLoading(false)
  }

  return (
    <Button
      Icon={loading ? NoticeLoading : Arrow}
      iconDirection="down"
      onClick={handleClick}
      data-testid={`show-more-${channelType}`}
    >
      {t('chat.show-more.label', 'View More')}
    </Button>
  )
}
