import { useEffect, useState } from 'react'
import { useEvent } from '@fs/zion-frontend-friends'
import { LOG_LEVEL } from '../../../global/chatLog'
import { queryParentChannels } from '../../../helpers/stream/streamChatChannelsHelper'
import useChatLog from '../../../hooks/useChatLog'
import { CHAT_ACTIONS } from '../../../hooks/useChatReducer'
import { useChatDispatch, useChatState } from '../../../providers/ChatStateProvider'

// Enriches threads with the isStreamThread flag
function enrichThreads(threads) {
  threads.forEach((thread) => {
    thread.isStreamThread = true
  })
  return threads
}

// Determines if a thread should be included based on parent channel existence and restrictions
function shouldIncludeThread(thread, allChannels, restrictToManagedGroups) {
  const parentCid = thread.state?.getLatestValue()?.channel?.cid

  const parentChannelExists = allChannels.some((ch) => ch.cid === parentCid)
  if (!parentChannelExists) return false

  return restrictToManagedGroups ? parentCid?.includes('fs_managed') : true
}

// Filters threads based on parent channel availability and access restrictions
function filterThreads(threads, existingChannels, newParentChannels, restrictToManagedGroups) {
  const allChannels = [...existingChannels, ...newParentChannels]
  return threads.filter((thread) => shouldIncludeThread(thread, allChannels, restrictToManagedGroups))
}

function useChatThreads() {
  const { client, channels, restrictToManagedGroups, nonQueryableChannelIds } = useChatState()
  const chatDispatch = useChatDispatch()
  const { log } = useChatLog({ component: 'useChatThreads' })

  const [hasMoreThreads, setHasMoreThreads] = useState(false)

  const threadManager = client?.threads

  const handleThreadStateChange = useEvent(async (nextState, isMounted) => {
    try {
      const latestThreads = nextState.threads || []

      const { parentChannels, parentChannelIdsNotFound } = await queryParentChannels({
        client,
        channels,
        threads: restrictToManagedGroups
          ? latestThreads.filter((thread) => thread.state?.getLatestValue()?.channel?.cid?.includes('fs_managed'))
          : latestThreads,
        nonQueryableChannelIds,
        log,
      })

      if (!isMounted) return

      chatDispatch({ type: CHAT_ACTIONS.UPSERT_CHANNELS, channels: parentChannels })

      const enrichedThreads = enrichThreads(latestThreads)
      const filteredThreads = filterThreads(enrichedThreads, channels, parentChannels, restrictToManagedGroups)

      const hasNextPage = !!nextState.pagination?.nextCursor
      const hasVisibleThreads = filteredThreads.length > 0
      setHasMoreThreads(hasNextPage && hasVisibleThreads)

      chatDispatch({
        type: CHAT_ACTIONS.SET_THREAD_LIST,
        threadList: filteredThreads,
        nonQueryableChannelIds: parentChannelIdsNotFound,
      })
    } catch (error) {
      log({ msg: `Error handling thread state change: ${error}`, level: LOG_LEVEL.ERROR })
    }
  })

  useEffect(() => {
    if (!threadManager) return () => {}

    let isMounted = true

    threadManager.activate()
    threadManager.registerSubscriptions()
    const unsubscribe = threadManager.state.subscribe((nextState) => handleThreadStateChange(nextState, isMounted))

    return () => {
      isMounted = false
      unsubscribe()
      threadManager.deactivate()
    }
  }, [threadManager, handleThreadStateChange])

  const loadMoreThreads = () => threadManager?.loadNextPage?.()

  return { hasMoreThreads, loadMoreThreads, threadManager }
}

export default useChatThreads
