import { Button, DialogOverlay, useOverlay, DataPreview, Skeleton, List } from '@fs/zion-ui'
import React, { useState } from 'react'
import { useTranslation } from 'react-i18next'
import ChatChannelListItems from './chat-window-chats/ChatChannelListItems'
import { CHANNEL_TYPE } from '../services/fsChat/fsChannelEnums'
import { useHandleSelectedSearchSuggestion } from '../hooks/useChatSearchChats'
import useGroupBrowserInfiniteList from './chat-window-chats/useGroupBrowserInfiniteList'
import useChatLog from '../hooks/useChatLog'

const GROUPS_PAGE_SIZE = 30 // the bigger this is, the more performant it is for the backend

function GroupsBrowser({ type, groupsBrowseOverlay }) {
  const { track } = useChatLog({ component: '[GroupsBrowser]' })
  const onItemSelect = useHandleSelectedSearchSuggestion()
  const { groups, loading, lastElementRef } = useGroupBrowserInfiniteList({ type })

  return (
    <DataPreview.Provider loading={loading && groups?.length === 0}>
      {/* LOADING PREVIEW */}
      <DataPreview.Loading>
        <ul style={{ minWidth: 200 }} aria-hidden="true">
          {Array(GROUPS_PAGE_SIZE)
            .fill()
            .map((_, i) => (
              // eslint-disable-next-line react/no-array-index-key -- these are readonly skeletons
              <Skeleton.ListItem key={i} dense hasAvatar hasSecondLine />
            ))}
        </ul>
      </DataPreview.Loading>

      {/* CONTENT WHEN LOADED */}
      <DataPreview.Ready>
        <List>
          <ChatChannelListItems
            list={groups}
            onItemSelect={(channel) => {
              track({ link_name: `Chat:View All ${type}:Select Chat` })
              onItemSelect({ channel })
              groupsBrowseOverlay.close()
            }}
            hideMenuIcon
            lastElementRef={lastElementRef}
            sortByLastMessage={false}
          />
        </List>
      </DataPreview.Ready>
    </DataPreview.Provider>
  )
}

export default function BrowseGroupsList({ type = CHANNEL_TYPE.FS_PUBLIC }) {
  const [t] = useTranslation()
  const [groupsBrowserContent, setGroupsBrowserContent] = useState()
  const groupsBrowseOverlay = useOverlay()
  const { track } = useChatLog({ component: '[BrowseGroupsList]' })
  const title =
    type === CHANNEL_TYPE.FS_ROOTSTECH
      ? t('chat.rootstech-groups.heading', 'RootsTech Groups')
      : t('chat.attendee-groups.heading', 'Attendee Groups')
  const buttonText = t('chat.view-all.button', 'View All')
  return (
    <>
      <Button
        data-testid={`view-all-${type}-groups-button`}
        onClick={async (event) => {
          track({ link_name: `Chat:View All ${type}` })
          setGroupsBrowserContent(<GroupsBrowser type={type} groupsBrowseOverlay={groupsBrowseOverlay} />)
          groupsBrowseOverlay.handleClick(event)
        }}
      >
        {buttonText}
      </Button>
      <DialogOverlay {...groupsBrowseOverlay} maxHeight={500} title={title}>
        <div>{groupsBrowserContent}</div>
      </DialogOverlay>
    </>
  )
}
