import React from 'react'
import { css } from '@linaria/core'
import { useTranslation } from 'react-i18next'
import { LayoutBand, List, colors } from '@fs/zion-ui'
import ChatWindowChatsExpandableListItems from './ChatWindowChatsExpandableListItems'
import { CHANNEL_CATEGORY_MAP } from '../../services/fsChat/fsChannelEnums'
import useChatFlags from '../../hooks/useChatFlags'
import { useMyChatsTabChannels } from '../../hooks/channelHooks'

const listItemResetCss = css`
  list-style: none;
  margin: 0;
  padding: 0;
`

// Shared events section used in both legacy and redesigned layouts
export default function ChatEventsSection({ channelMenuItemProps }) {
  const [t] = useTranslation()
  const { chatAskUsAnythingIsOn } = useChatFlags()
  const { rootsTechSessionChannels, rootsTechChannels, askUsAnythingChannels, generalPublicChannels, vendorChannels } =
    useMyChatsTabChannels()
  return (
    <li className={listItemResetCss}>
      <LayoutBand color={colors.red02}>
        <List>
          <ChatWindowChatsExpandableListItems
            {...channelMenuItemProps}
            category={CHANNEL_CATEGORY_MAP.rootsTechSessionChannels}
            list={rootsTechSessionChannels}
            heading={t('chat.session.heading', 'Session Chats - RootsTech')}
            isEventList
          />
          <ChatWindowChatsExpandableListItems
            {...channelMenuItemProps}
            category={CHANNEL_CATEGORY_MAP.rootsTechChannels}
            list={rootsTechChannels}
            heading={t('chat.rootstech-groups.heading', 'RootsTech Groups')}
            isEventList
          />
          {chatAskUsAnythingIsOn && (
            <ChatWindowChatsExpandableListItems
              {...channelMenuItemProps}
              category={CHANNEL_CATEGORY_MAP.askUsAnythingChannels}
              list={askUsAnythingChannels}
              heading={t('chat.ask-us-anything.heading', 'Ask Us Anything - RootsTech')}
              isEventList
            />
          )}
          <ChatWindowChatsExpandableListItems
            {...channelMenuItemProps}
            category={CHANNEL_CATEGORY_MAP.attendeeCreatedChannels}
            list={generalPublicChannels}
            heading={t('chat.groups.action', 'Attendee Groups - RootsTech')}
            isEventList
          />
          <ChatWindowChatsExpandableListItems
            {...channelMenuItemProps}
            category={CHANNEL_CATEGORY_MAP.vendorChannels}
            list={vendorChannels}
            heading={t('chat.exhibitors.heading', 'Expo Hall - RootsTech')}
            isEventList
          />
        </List>
      </LayoutBand>
    </li>
  )
}
