import React from 'react'
import { colors, Button } from '@fs/zion-ui'
import { ContentCompose } from '@fs/zion-icon'
import { css } from '@linaria/core'
import { useHistory } from '@fs/zion-router'
import { useTranslation } from 'react-i18next'
import { trackEvent } from '@fs/zion-analytics'
import { useChatState } from '../providers/ChatStateProvider'
import { CHANNEL_TYPE } from '../services/fsChat/fsChannelEnums'
import { buildChatRoute, CHAT_ROUTE_KEY } from '../chat-memory-router/ChatMemoryRouter'

const EditIcon = () => <ContentCompose color={colors.color70} />
const createButtonCss = css`
  display: flex;
  justify-content: center;
  padding: 0 0 5px 0;
`

export default function ChatWindowCreateChatListItem({ groupTag, ...props }) {
  const [t] = useTranslation()
  const { createChatRecipientChipCollection } = useChatState()
  const history = useHistory()

  const onClickPublic = () => {
    createChatRecipientChipCollection.resetChips()
    trackEvent({
      event_name: 'click_action',
      link_name: `Chat:Click Create of type ${groupTag}`,
      path: buildChatRoute(CHAT_ROUTE_KEY.CREATE_EMPTY_GROUP_CHAT),
    })
    history.push(buildChatRoute(CHAT_ROUTE_KEY.CREATE_EMPTY_GROUP_CHAT))
  }

  const onClickPrivate = () => {
    createChatRecipientChipCollection.resetChips()
    trackEvent({
      event_name: 'click_action',
      link_name: 'Chat:Click Create of type direct',
    })
    history.push(buildChatRoute(CHAT_ROUTE_KEY.CREATE_EMPTY_DIRECT_CHAT))
  }

  return (
    <li className={createButtonCss}>
      <Button
        onClick={groupTag === CHANNEL_TYPE.FS_DIRECT ? onClickPrivate : onClickPublic}
        Icon={EditIcon}
        emphasis="low"
        {...props}
      >
        {groupTag === CHANNEL_TYPE.FS_DIRECT
          ? t('chat.create-private-chat.action', 'Create Private Chat')
          : t('chat.create-public-group.action', 'Create Public Chat')}
      </Button>
    </li>
  )
}
