import { useOverlay } from '@fs/zion-ui'
import React, { useState, Suspense } from 'react'
// TODO: figure out if we can dynamically import zion-rreport-abuse-overlay here. Because ChatMessageOverlay.js is doing a dynamic import
// of it. and if we do a regular static import here, we are most likely losing the benefits of dynamic importing over in ChatMessageOverlay.js
/* eslint-disable-next-line @nx/enforce-module-boundaries -- ignoring for now, and making a note to potentially fix in the future */
import ReportAbuseOverlay from '@fs/zion-report-abuse-overlay'
import { FallbackOverlay } from '@fs/zion-usabilla'
import { useChannelActions } from '../../hooks/channelHooks'
import { useChatState } from '../../providers/ChatStateProvider'
import { getChannelMembers, hasPendingInvite } from '../../helpers/stream/streamChatHelper'

const ChatChannelInviteMenuOverlay = React.lazy(() => import('./ChatChannelInviteMenuOverlay'))
const ChatChannelActionsMenuOverlay = React.lazy(() => import('../../chat-actions/ChatChannelActionsMenuOverlay'))
const ChatBlockUserOverlay = React.lazy(() => import('./ChatBlockUserOverlay'))

ChatChannelInviteMenuOverlay.displayName = 'ChatChannelInviteMenuOverlay'
ChatChannelActionsMenuOverlay.displayName = 'ChatChannelActionsMenuOverlay'
ChatBlockUserOverlay.displayName = 'ChatBlockUserOverlay'

export default function ChatChannelMenu({ menuOverlay, channel, isHeader }) {
  const [reportAbuseAdditionalInfo, setReportAbuseAdditionalInfo] = useState()
  const reportAbuseOverlay = useOverlay()
  const blockUserOverlay = useOverlay()
  const usabillaFallbackOverlay = useOverlay()
  const { displayChannelActionsMenu } = useChannelActions({ channel, isHeader })
  const { client } = useChatState()
  const isInvite = hasPendingInvite({ channel, userId: client?.userID })

  if (isInvite) {
    return (
      <Suspense fallback={null}>
        <ChatChannelInviteMenuOverlay menuOverlay={menuOverlay} channel={channel} isHeader={isHeader} />
      </Suspense>
    )
  }
  return displayChannelActionsMenu ? (
    <Suspense fallback={null}>
      {(menuOverlay.isOpen || menuOverlay.transitioning) && (
        <ChatChannelActionsMenuOverlay
          channel={channel}
          isHeader={isHeader}
          menuOverlay={menuOverlay}
          reportAbuseOverlay={reportAbuseOverlay}
          setReportAbuseAdditionalInfo={setReportAbuseAdditionalInfo}
          blockUserOverlay={blockUserOverlay}
          usabillaFallbackOverlay={usabillaFallbackOverlay}
        />
      )}
      {/* ReportAbuseOverlay's success message breaks if conditionally rendered */}
      <ReportAbuseOverlay
        overlay={reportAbuseOverlay}
        subject="Report Abuse for Chat"
        additionalInfo={reportAbuseAdditionalInfo}
      />
      {(blockUserOverlay.isOpen || blockUserOverlay.transitioning) && (
        <ChatBlockUserOverlay
          overlay={blockUserOverlay}
          targetUser={getChannelMembers({ channel, excludeUserId: client?.userID })?.[0]?.user}
        />
      )}
      {(usabillaFallbackOverlay.isOpen || usabillaFallbackOverlay.transitioning) && (
        <FallbackOverlay
          communityLink="https://community.familysearch.org/en/discussions/tagged/chat/p1"
          {...usabillaFallbackOverlay}
        />
      )}
    </Suspense>
  ) : null
}
