import React, { useCallback, useEffect, useMemo } from 'react'
import { useTranslation } from 'react-i18next'
import { ExpandableListItem, Row, Bleedable } from '@fs/zion-ui'
import { useParams } from '@fs/zion-router'
import { css } from '@linaria/core'
import { useChatChannelExpander } from '../../providers/ChatChannelExpanderProvider'
import ChatChannelListItems from './ChatChannelListItems'
import { useChatState } from '../../providers/ChatStateProvider'
import { CHANNEL_TYPE } from '../../services/fsChat/fsChannelEnums'
import ShowMoreChannels from '../ShowMoreChannels'
import useChatFlags from '../../hooks/useChatFlags'

const listItemClass = css`
  list-style: none;
`

export default function ChatWindowChatsThreadsListItems({ hasMoreThreads, onShowMore, ...props }) {
  const [t] = useTranslation()
  const { pid } = useParams()
  const { threadList } = useChatState()
  const { expandable, updateExpandableItem } = useChatChannelExpander()
  const { messagingChatLeftPanelRedesignIsOn } = useChatFlags()

  const heading = t('chat.my-chat-threads.heading', 'Threads')
  const channelType = CHANNEL_TYPE.FS_THREAD

  const setOpen = useCallback(
    (isOpen) => {
      updateExpandableItem({ isOpen, key: channelType })
    },
    [updateExpandableItem, channelType]
  )
  const containsSelectedChannel = useMemo(
    () => Boolean(threadList?.find((thread) => thread.state?.getLatestValue()?.parentMessage?.id === pid)),
    [threadList, pid]
  )
  useEffect(() => {
    if (containsSelectedChannel) {
      setOpen(true)
    }
  }, [containsSelectedChannel, setOpen])

  const unreadCount = threadList.reduce((count, thread) => {
    const ownUnread = thread?.ownUnreadCount || 0
    return ownUnread > 0 ? count + 1 : count
  }, 0)
  const emphasized = Boolean(unreadCount)
  const countString = emphasized ? ` (${unreadCount})` : ''
  const overline = `${heading}${countString}`
  const open = expandable[channelType]

  const showMoreButton = hasMoreThreads
  return (
    <>
      {!messagingChatLeftPanelRedesignIsOn && (
        <ExpandableListItem
          primaryText={' '}
          setOpen={() => setOpen(!open)}
          open={open}
          overline={overline}
          emphasized={emphasized}
          dense
          data-testid="chat-list-item-unread"
        >
          <>
            <ChatChannelListItems list={threadList} sortByLastMessage={false} {...props} />

            {showMoreButton && (
              <li className={listItemClass}>
                <Bleedable top={12}>
                  <Row alignX="center">
                    <ShowMoreChannels channelType={channelType} handleShowMoreClick={onShowMore} />
                  </Row>
                </Bleedable>
              </li>
            )}
          </>
        </ExpandableListItem>
      )}
      {messagingChatLeftPanelRedesignIsOn && (
        <>
          <ChatChannelListItems list={threadList} sortByLastMessage={false} {...props} />

          {showMoreButton && (
            <li className={listItemClass}>
              <Bleedable top={12}>
                <Row alignX="center">
                  <ShowMoreChannels channelType={channelType} handleShowMoreClick={onShowMore} />
                </Row>
              </Bleedable>
            </li>
          )}
        </>
      )}
    </>
  )
}
