import { useCallback, useEffect, useRef, useState } from 'react'
import { queryChannelsByType, QUERY_CHANNELS_PAGE_SIZE } from '../../helpers/stream/streamChatChannelsHelper'
import { useChatState } from '../../providers/ChatStateProvider'
import useHandleChatErrors from '../../hooks/useHandleChatErrors'
import useChatLog from '../../hooks/useChatLog'

const hasMoreChannels = (lastNumberOfMessagesRead) => lastNumberOfMessagesRead >= QUERY_CHANNELS_PAGE_SIZE

export default function useGroupBrowserInfiniteList({ type }) {
  const [groups, setGroups] = useState([])
  const [loading, setLoading] = useState(false)
  const [hasMore, setHasMore] = useState(false)
  const [offset, setOffset] = useState(0)
  const { client } = useChatState()
  const { log } = useChatLog({ component: '[useGroupBrowserInfiniteList]' })
  const { handleBasicError } = useHandleChatErrors({ log })
  const groupsLength = groups?.length || 0

  useEffect(() => {
    let isUnmounted = false

    const getGroupChannels = async () => {
      if (!isUnmounted) {
        setLoading(true)
      }

      try {
        const newGroups = await queryChannelsByType({ client, type, offset, log })

        if (!isUnmounted) {
          setGroups((oldGroups) => {
            return [...oldGroups, ...newGroups]
          })
          setHasMore(hasMoreChannels(newGroups?.length))
          setLoading(false)
        }
      } catch (err) {
        if (!isUnmounted) {
          handleBasicError(err, { moreInfo: `Problem paginating through groups. Type: ${type}` })
          setLoading(false)
        }
      }
    }

    if (client && type) {
      getGroupChannels()
    }

    return () => {
      isUnmounted = true
    }
  }, [handleBasicError, type, client, offset, log])

  const observer = useRef()

  // Cleanup observer on unmount
  useEffect(() => {
    return () => {
      if (observer.current) {
        observer.current.disconnect()
      }
    }
  }, [])

  useEffect(() => {
    let isUnmounted = false

    if (!isUnmounted) {
      setLoading(true)
      setOffset(0)
      setGroups([])
      setHasMore(false)
    }

    return () => {
      isUnmounted = true
    }
  }, [type])

  // This function gets called everytime our lastElementRef is rendered
  const lastElementRef = useCallback(
    (node) => {
      if (!loading) {
        if (observer.current) {
          observer.current.disconnect()
        }
        observer.current = new IntersectionObserver((entries) => {
          if (entries[0].isIntersecting && hasMore) {
            setOffset(groupsLength)
          }
        })
        if (node) {
          observer.current.observe(node)
        }
      }
    },
    [loading, hasMore, groupsLength]
  )

  return {
    loading,
    groups,
    lastElementRef,
  }
}
