import React, { useCallback, useEffect, useMemo } from 'react'
import { useTranslation } from 'react-i18next'
import { Button, ExpandableListItem, Skeleton, Row, Bleedable } from '@fs/zion-ui'
import { MenuNewWindow } from '@fs/zion-icon'
import { useParams } from '@fs/zion-router'
import { css } from '@linaria/core'
import { useChatChannelExpander } from '../../providers/ChatChannelExpanderProvider'
import useChatFlags from '../../hooks/useChatFlags'
import ChatChannelListItems from './ChatChannelListItems'
import BrowseGroupsList from '../BrowseGroupsList'
import ChatWindowCreateChatListItem from '../ChatWindowCreateChatListItem'
import { useChatState, useChatDispatch } from '../../providers/ChatStateProvider'
import { CHAT_ACTIONS } from '../../hooks/useChatReducer'
import { cidMatchesChannel, getChannelUnreadCount } from '../../helpers/stream/streamChatHelper'
import { queryPageOfChannelsByType, QUERY_CHANNELS_PAGE_SIZE } from '../../helpers/stream/streamChatChannelsHelper'
import ChatAskUsAnythingListItem from './ChatAskUsAnythingListItem'
import { CHANNEL_TYPE } from '../../services/fsChat/fsChannelEnums'
import ShowMoreChannels from '../ShowMoreChannels'
import useChatLog from '../../hooks/useChatLog'

const listItemClass = css`
  list-style: none;
`

const useHandleShowMore = (category) => {
  const chatDispatch = useChatDispatch()
  const { client, channels, hasMoreChannels } = useChatState()
  const { log } = useChatLog({ component: '[ChatWindowChatsExpandableListItems.useHandleShowMore]' })

  const handleShowMoreClick = async () => {
    const offset = channels.filter((c) => category.types.includes(c.type)).length
    const newChannels = await queryPageOfChannelsByType({
      client,
      types: category.types,
      offset,
      log,
    })
    const newHasMoreChannels = { ...hasMoreChannels, [category.key]: newChannels.length === QUERY_CHANNELS_PAGE_SIZE }
    const merged = [...channels, ...newChannels]
    const deduped = merged.filter((ch, i, arr) => arr.findIndex((c) => c.cid === ch.cid) === i)
    chatDispatch({
      type: CHAT_ACTIONS.SET_CHANNELS,
      channels: deduped,
      hasMoreChannels: newHasMoreChannels,
    })
  }

  return useCallback(handleShowMoreClick, [category, channels, client, chatDispatch, hasMoreChannels, log])
}

export default function ChatWindowChatsExpandableListItems({ category, heading, list, isEventList, ...props }) {
  const [t] = useTranslation()
  const { cid: selectedCid } = useParams()
  const { channelsLoading, hasMoreChannels } = useChatState()
  const { expandable, updateExpandableItem } = useChatChannelExpander()
  const { chatBrowseExpoHallIsOn, chatBrowseSessionsIsOn, messagingChatCreatePublicGroupIsOn } = useChatFlags()
  const { track } = useChatLog({ component: '[ChatWindowChatsExpandableListItems]' })

  const handleShowMoreClick = useHandleShowMore(category)

  const setOpen = useCallback(
    (isOpen) => {
      updateExpandableItem({ isOpen, key: category?.key })
    },
    [category?.key, updateExpandableItem]
  )
  const unreadCount = list?.filter((channel) => getChannelUnreadCount({ channel }) > 0).length ?? 0
  const emphasized = Boolean(unreadCount)
  const countString = emphasized ? ` (${unreadCount})` : ''
  const overline = `${heading}${countString}`
  const open = expandable[category?.key]

  const containsSelectedChannel = useMemo(
    () => Boolean(list?.find((channel) => cidMatchesChannel({ cid: selectedCid, channel }))),
    [list, selectedCid]
  )
  useEffect(() => {
    if (containsSelectedChannel) {
      setOpen(true)
    }
  }, [containsSelectedChannel, selectedCid, setOpen])

  const showMoreButton = hasMoreChannels?.[category?.key]
  const showBrowseButton = category?.key === CHANNEL_TYPE.FS_PUBLIC || category?.key === CHANNEL_TYPE.FS_ROOTSTECH
  const showExpoHallButton = category?.key === CHANNEL_TYPE.FS_VENDOR && chatBrowseExpoHallIsOn
  const showSessionsButtons = chatBrowseSessionsIsOn && category?.key === CHANNEL_TYPE.FS_SESSION
  const showFooterButton = showMoreButton || showBrowseButton || showExpoHallButton || showSessionsButtons
  return (
    <ExpandableListItem
      primaryText={' '}
      setOpen={() => setOpen(!open)}
      open={open}
      overline={overline}
      emphasized={emphasized}
      dense
      data-testid={`chat-list-item-${category?.key || 'unread'}`}
    >
      <>
        {category?.key === CHANNEL_TYPE.FS_PUBLIC && messagingChatCreatePublicGroupIsOn && (
          <ChatWindowCreateChatListItem data-testid="create-public-chat-list-item" groupTag={category?.key} />
        )}
        {category?.key === CHANNEL_TYPE.FS_DIRECT && (
          <ChatWindowCreateChatListItem data-testid="create-direct-chat-list-item" groupTag={category?.key} />
        )}
        {category?.key === CHANNEL_TYPE.FS_SUPPORT && <ChatAskUsAnythingListItem />}
        {channelsLoading ? (
          <ul aria-hidden="true">
            <Skeleton.ListItem dense hasAvatar hasSecondLine />
            <Skeleton.ListItem dense hasAvatar hasSecondLine />
            <Skeleton.ListItem dense hasAvatar hasSecondLine />
          </ul>
        ) : (
          <ChatChannelListItems list={list} isEventList {...props} />
        )}

        {showFooterButton && (
          <li className={listItemClass}>
            <Bleedable top={12}>
              <Row alignX="center">
                {showMoreButton && (
                  <ShowMoreChannels channelType={category?.key} handleShowMoreClick={handleShowMoreClick} />
                )}
                {showBrowseButton && <BrowseGroupsList type={category?.key} />}
                {showExpoHallButton && (
                  <Button
                    emphasis="low"
                    Icon={MenuNewWindow}
                    to="/rootstech/expohall/"
                    external
                    target="_blank"
                    onClick={() => {
                      track({ link_name: 'Chat:Open Expo Hall' })
                    }}
                  >
                    {t('chat.open-expo-hall.action', 'Open Expo Hall')}
                  </Button>
                )}
                {showSessionsButtons && (
                  <Button
                    data-testid="find-session-speakers-button"
                    emphasis="low"
                    Icon={MenuNewWindow}
                    to="/rootstech/speakers/"
                    external
                    target="_blank"
                    onClick={() => {
                      track({ link_name: 'Chat:Find Speakers' })
                    }}
                  >
                    {t('chat.find-speakers.button', 'Find Speakers')}
                  </Button>
                )}
              </Row>
            </Bleedable>
          </li>
        )}
      </>
    </ExpandableListItem>
  )
}
