import React, { useCallback } from 'react'
import { css } from '@linaria/core'
import { Bleedable, Row } from '@fs/zion-ui'
import { TAB_CATEGORY, CHANNEL_TYPE } from '../../services/fsChat/fsChannelEnums'
import ChatChannelListItems from './ChatChannelListItems'
import ChatWindowChatsThreadsListItems from './ChatWindowChatsThreadsListItems'
import ChatEventsSection from './ChatEventsSection'
import { useChatState, useChatDispatch } from '../../providers/ChatStateProvider'
import LoadingSpinner from '../LoadingSpinner'
import ShowMoreChannels from '../ShowMoreChannels'
import { loadChannelsForCategory, QUERY_CHANNELS_PAGE_SIZE } from '../../helpers/stream/streamChatChannelsHelper'
import { CHAT_ACTIONS } from '../../hooks/useChatReducer'
import { getChannelUnreadCount } from '../../helpers/stream/streamChatHelper'
import useChatLog from '../../hooks/useChatLog'

const chatChannelsWrapperCss = css`
  padding: 0 12px;
`

const useHandleShowMore = (category) => {
  const chatDispatch = useChatDispatch()
  const { client, channels, restrictToManagedGroups } = useChatState()
  const { log } = useChatLog({ component: '[useHandleShowMore]' })

  const handleShowMoreClick = async () => {
    let offset = 0
    switch (category) {
      case TAB_CATEGORY.ALL:
        offset = channels.length
        break
      case TAB_CATEGORY.UNREAD:
        offset = channels.filter((c) => getChannelUnreadCount({ channel: c }) > 0).length
        break
      case TAB_CATEGORY.DIRECT:
        offset = channels.filter((c) => c.type === CHANNEL_TYPE.FS_DIRECT).length
        break
      case TAB_CATEGORY.FAMILY_GROUPS:
        offset = channels.filter((c) => c.type === CHANNEL_TYPE.FS_MANAGED).length
        break
      default:
    }

    const newChannels = await loadChannelsForCategory({
      category,
      client,
      offset,
      restrictToManagedGroups,
      log,
    })
    const newHasMoreChannels = { [category]: newChannels.length >= QUERY_CHANNELS_PAGE_SIZE }
    chatDispatch({
      type: CHAT_ACTIONS.UPSERT_CHANNELS,
      channels: newChannels,
      hasMoreChannels: newHasMoreChannels,
    })
  }

  return useCallback(handleShowMoreClick, [category, client, chatDispatch, channels, restrictToManagedGroups, log])
}

export default function ChatWindowChatsTab({
  chatList,
  channelMenuItemProps,
  chatCategory,
  restrictToManagedGroups,
  hasMoreThreads,
  loadMoreThreads,
}) {
  const { hasMoreChannels, channelsLoading } = useChatState()
  const handleShowMoreClick = useHandleShowMore(chatCategory)
  const showMoreButton = hasMoreChannels?.[chatCategory]

  if (channelsLoading) {
    return <LoadingSpinner />
  }

  let content = null

  switch (chatCategory) {
    case TAB_CATEGORY.THREADS:
      content = (
        <div className={chatChannelsWrapperCss}>
          <ChatWindowChatsThreadsListItems
            {...channelMenuItemProps}
            hasMoreThreads={hasMoreThreads}
            onShowMore={loadMoreThreads}
          />
        </div>
      )
      break
    case TAB_CATEGORY.EVENTS:
      if (!restrictToManagedGroups) {
        content = <ChatEventsSection channelMenuItemProps={channelMenuItemProps} />
      }
      break
    default:
      content = (
        <div className={chatChannelsWrapperCss}>
          <ChatChannelListItems list={chatList} sortByLastMessage {...channelMenuItemProps} />
          {showMoreButton && (
            <Bleedable top={12}>
              <Row alignX="center">
                <ShowMoreChannels channelType={chatCategory} handleShowMoreClick={handleShowMoreClick} />
              </Row>
            </Bleedable>
          )}
        </div>
      )
  }

  return content
}
