import React, { useEffect, useState, useMemo } from 'react'
import { BillboardText, colors, List, useTheme, useMenuOverlay } from '@fs/zion-ui'
import { css } from '@linaria/core'
import { useTranslation } from 'react-i18next'
import { VisuallyHidden } from '@reach/visually-hidden'
import { useChatState, useChatDispatch } from '../../providers/ChatStateProvider'
import useChatFlags from '../../hooks/useChatFlags'
import { useMyChatsTabChannels, useOpenExistingChannel } from '../../hooks/channelHooks'
import ChatWindowChatsExpandableListItems from './ChatWindowChatsExpandableListItems'
import ChatWindowChatsThreadsListItems from './ChatWindowChatsThreadsListItems'
import {
  CHANNEL_CATEGORY_MAP,
  CHANNEL_TYPE,
  TAB_CATEGORY,
  EVENT_CHANNEL_TYPES,
} from '../../services/fsChat/fsChannelEnums'
import ChatChannelMenu from './ChatChannelMenu'
import { loadChannelsForCategory, QUERY_CHANNELS_PAGE_SIZE } from '../../helpers/stream/streamChatChannelsHelper'
import { sortChannelsAndThreadsByLastUpdated, getUnreadChannels } from '../../helpers/stream/streamChatHelper'
import { CHAT_ACTIONS } from '../../hooks/useChatReducer'
import ChatEventsSection from './ChatEventsSection'
import ChatWindowChatsTab from './ChatWindowChatsTab'
import useHandleChatErrors from '../../hooks/useHandleChatErrors'
import useChatThreads from './hooks/useChatThreads'
import useChatLog from '../../hooks/useChatLog'

// to prevent horizontal overflow of list items which causes an ugly scrollbar
const listOverrideCss = css`
  & li {
    margin: 0;
  }
  /* hide horizontal rule above first list */
  & ul > li:first-of-type {
    padding: 0;
  }
  & ul > li:first-of-type [class^='dividerCss'] {
    border-top: unset;
  }
  & [class^='sideCar'] [class^='metaText'] {
    align-self: center;
  }

  /* FSCHAT-309: On iPhone or Android cannot open the chat menu when at bottom of screen
   * The solution is to put a margin below the chats lists.
   */
  & {
    margin-bottom: 120px;
  }
`

// Trying to keep this somewhat organized
// Old layout: to be removed when redesign is fully rolled out
function LegacyLeftPanel({
  channelMenuItemProps,
  privateChannels,
  familySearchGroups,
  combinedUnread,
  restrictToManagedGroups,
  showEvents,
  hasMoreThreads,
  loadMoreThreads,
}) {
  const [t] = useTranslation()
  return (
    <>
      <List>
        <ChatWindowChatsExpandableListItems
          {...channelMenuItemProps}
          list={combinedUnread}
          heading={t('chat.my-unread-chats.heading', 'Unread')}
          isInUnreadList
        />
        {!restrictToManagedGroups && (
          <ChatWindowChatsExpandableListItems
            {...channelMenuItemProps}
            category={CHANNEL_CATEGORY_MAP.privateChannels}
            list={privateChannels}
            heading={t('chat.my-chats.heading', 'Private')}
          />
        )}
        <ChatWindowChatsExpandableListItems
          {...channelMenuItemProps}
          category={CHANNEL_CATEGORY_MAP.familySearchGroups}
          list={familySearchGroups}
          heading={t('chat.familysearch-groups.heading', 'Family Groups')}
        />
        <ChatWindowChatsThreadsListItems
          {...channelMenuItemProps}
          hasMoreThreads={hasMoreThreads}
          onShowMore={loadMoreThreads}
        />
      </List>

      {showEvents && !restrictToManagedGroups && <ChatEventsSection channelMenuItemProps={channelMenuItemProps} />}
    </>
  )
}

function calculateHasMoreChannels(chatCategory, newChannels) {
  if (chatCategory === TAB_CATEGORY.EVENTS) {
    const hasMoreByType = {}
    EVENT_CHANNEL_TYPES.forEach((type) => {
      const channelsOfType = newChannels.filter((c) => c.type === type)
      hasMoreByType[type] = channelsOfType.length >= QUERY_CHANNELS_PAGE_SIZE
    })
    return hasMoreByType
  }

  const hasMore = newChannels.length >= QUERY_CHANNELS_PAGE_SIZE
  return { [chatCategory]: hasMore }
}

function dispatchChannelLoadSuccess(chatDispatch, chatCategory, newChannels) {
  const hasMoreChannels = calculateHasMoreChannels(chatCategory, newChannels)
  chatDispatch({
    type: CHAT_ACTIONS.LOAD_CATEGORY_CHANNELS_SUCCESS,
    category: chatCategory,
    channels: newChannels,
    hasMoreChannels,
  })
}

function handleChannelLoadError(handleBasicError, chatDispatch, err, chatCategory) {
  handleBasicError(err, {
    moreInfo: 'Problem loading channels for category',
    category: chatCategory,
  })
  chatDispatch({ type: CHAT_ACTIONS.SET_HAS_LOADED_CATEGORY, category: chatCategory })
}

async function fetchChannelsForCategory({
  category,
  client,
  restrictToManagedGroups,
  chatDispatch,
  handleBasicError,
  isCancelled,
  log,
}) {
  chatDispatch({ type: CHAT_ACTIONS.SET_LOADING_CHANNELS, isLoading: true })

  try {
    const newChannels = await loadChannelsForCategory({ category, client, restrictToManagedGroups, log })
    if (isCancelled()) return

    dispatchChannelLoadSuccess(chatDispatch, category, newChannels)
  } catch (err) {
    if (!isCancelled()) {
      handleChannelLoadError(handleBasicError, chatDispatch, err, category)
    }
  } finally {
    chatDispatch({ type: CHAT_ACTIONS.SET_LOADING_CHANNELS, isLoading: false })
  }
}

export default function ChatWindowChats() {
  const [t] = useTranslation()
  const channelMenuOverlay = useMenuOverlay()
  const [channelMenuChannel, setChannelMenuChannel] = useState()
  const openExistingChannel = useOpenExistingChannel()
  const { showEvents, restrictToManagedGroups, threadList, channels, client } = useChatState()
  const chatDispatch = useChatDispatch()
  const { log } = useChatLog({ component: '[ChatWindowChats]' })
  const { handleBasicError } = useHandleChatErrors({ log })
  const { hasMoreThreads, loadMoreThreads } = useChatThreads()
  const allUnreadChannels = getUnreadChannels({ channels, restrictToManagedGroups })
  const allUnreadThreads = threadList.filter((thread) => thread?.ownUnreadCount > 0)
  const combinedUnread = sortChannelsAndThreadsByLastUpdated([...allUnreadChannels, ...allUnreadThreads])
  const { chatCategory, hasLoadedCategory } = useChatState()
  const { messagingChatLeftPanelRedesignIsOn } = useChatFlags()
  const { privateChannels, familySearchGroups } = useMyChatsTabChannels()
  // Strict fs_direct only — privateChannels above intentionally includes fs_helper_connect for the legacy left panel.
  const directChannels = useMemo(() => channels.filter((c) => c.type === CHANNEL_TYPE.FS_DIRECT), [channels])

  const mergedChannelsAndThreads = useMemo(
    () => sortChannelsAndThreadsByLastUpdated([...channels, ...threadList]),
    [channels, threadList]
  )

  let chatList
  if (chatCategory === TAB_CATEGORY.ALL)
    chatList = messagingChatLeftPanelRedesignIsOn ? mergedChannelsAndThreads : channels
  if (chatCategory === TAB_CATEGORY.UNREAD) chatList = combinedUnread
  if (chatCategory === TAB_CATEGORY.DIRECT) chatList = directChannels
  if (chatCategory === TAB_CATEGORY.FAMILY_GROUPS) chatList = familySearchGroups
  if (chatCategory === TAB_CATEGORY.THREADS) chatList = threadList

  const theme = useTheme()
  const listItemTextColor = theme === 'day' ? colors.gray100 : colors.transparent.gray70
  const channelMenuItemProps = {
    onItemSelect: openExistingChannel,
    channelMenuOverlay,
    onChannelMenuSelect: setChannelMenuChannel,
  }

  useEffect(() => {
    let cancelled = false
    const shouldLoad = messagingChatLeftPanelRedesignIsOn && !hasLoadedCategory[chatCategory] && !!client

    if (shouldLoad) {
      fetchChannelsForCategory({
        category: chatCategory,
        client,
        restrictToManagedGroups,
        chatDispatch,
        handleBasicError,
        isCancelled: () => cancelled,
        log,
      })
    }

    return () => {
      cancelled = true
    }
  }, [
    chatCategory,
    hasLoadedCategory,
    chatDispatch,
    client,
    messagingChatLeftPanelRedesignIsOn,
    handleBasicError,
    restrictToManagedGroups,
    log,
  ])

  return (
    <div className={listOverrideCss}>
      <VisuallyHidden as="h3">{t('chat.chat-list.heading', 'Chat List')}</VisuallyHidden>
      <BillboardText primaryColor={listItemTextColor}>
        {messagingChatLeftPanelRedesignIsOn ? (
          <ChatWindowChatsTab
            chatList={chatList}
            channelMenuItemProps={channelMenuItemProps}
            chatCategory={chatCategory}
            restrictToManagedGroups={restrictToManagedGroups}
            hasMoreThreads={hasMoreThreads}
            loadMoreThreads={loadMoreThreads}
          />
        ) : (
          <LegacyLeftPanel
            channelMenuItemProps={channelMenuItemProps}
            privateChannels={privateChannels}
            familySearchGroups={familySearchGroups}
            combinedUnread={combinedUnread}
            restrictToManagedGroups={restrictToManagedGroups}
            showEvents={showEvents}
            hasMoreThreads={hasMoreThreads}
            loadMoreThreads={loadMoreThreads}
          />
        )}
        <ChatChannelMenu menuOverlay={channelMenuOverlay} channel={channelMenuChannel} />
      </BillboardText>
    </div>
  )
}
