import { HelpAskQuestion } from '@fs/zion-icon'
import { useHistory, useRouteMatch } from '@fs/zion-router'
import { colors, ListItem } from '@fs/zion-ui'
import React from 'react'
import { useTranslation } from 'react-i18next'
import useChatFlags from '../../hooks/useChatFlags'
import { CHAT_ROUTE_KEY, buildChatRoute } from '../../chat-memory-router/ChatMemoryRouter'
import useChatLog from '../../hooks/useChatLog'

const AUAHeaderIconButton = () => <HelpAskQuestion background={colors.blue30} emphasis="high" />

export default function ChatAskUsAnythingListItem() {
  const { messagingChatAUAButtonIsOn } = useChatFlags()
  const [t] = useTranslation()
  const history = useHistory()
  const isOnAUARoute = useRouteMatch(buildChatRoute(CHAT_ROUTE_KEY.CREATE_SUPPORT_CHAT))
  const { track } = useChatLog({ component: '[BrowseGroupsList]' })

  if (!messagingChatAUAButtonIsOn) return null

  return (
    <ListItem
      dense
      aria-label={t('chat.ask-us-anything.heading', 'Ask Us Anything - RootsTech')}
      data-testid="ask-us-anything"
      selected={!!isOnAUARoute}
      startElement={<ListItem.Icon Icon={AUAHeaderIconButton} aria-disabled="true" />}
      primaryText={t('chat.ask-us-anything.heading', 'Ask Us Anything - RootsTech')}
      secondaryText={t('chat.type-your-question.label', 'Type your question')}
      onClick={() => {
        track({ link_name: 'Chat:Click New fs_support Chat' })
        history.replace(buildChatRoute(CHAT_ROUTE_KEY.CREATE_SUPPORT_CHAT))
      }}
    />
  )
}
